import os
from cryptography.fernet import Fernet

# Load the encryption key from configuration
def get_encryption_key():
    return os.environ.get("ENCRYPTION_KEY").encode()

def encrypt_credit_card(credit_card_number):
    key = get_encryption_key()
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(credit_card_number.encode())
    return encrypted_card

def decrypt_credit_card(encrypted_card):
    key = get_encryption_key()
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card